# Conceptual sketch of Neural Cleanse-style trigger reversal
# (actual implementation uses gradient descent over input space)

import numpy as np

def estimate_trigger_size(model, tokenizer,
                          clean_inputs: list[str],
                          target_label: int,
                          n_tokens: int = 5) -> float:
    total_change = 0.0
    for text in clean_inputs:
        # Try all n_token insertions that flip prediction to target_label
        # (simplified: in practice, use gradient-guided search)
        best_perturbation = find_min_perturbation(
            model, tokenizer, text, target_label, n_tokens
        )
        total_change += best_perturbation
    return total_change / len(clean_inputs)

def find_min_perturbation(model, tokenizer, text, target, k):
    # Placeholder: returns a cost score for the smallest trigger found
    return np.random.uniform(0.1, 2.0)

def detect_backdoor(model, tokenizer,
                     clean_inputs: list[str],
                     n_classes: int) -> dict:
    sizes = {
        label: estimate_trigger_size(model, tokenizer, clean_inputs, label)
        for label in range(n_classes)
    }
    mean = np.mean(list(sizes.values()))
    std  = np.std(list(sizes.values()))
    anomaly_index = {
        label: abs(size - mean) / (std + 1e-8)
        for label, size in sizes.items()
    }
    # A label with anomaly index > 2 is a backdoor candidate
    suspects = {k: v for k, v in anomaly_index.items() if v > 2.0}
    return {'anomaly_index': anomaly_index, 'suspected_targets': suspects}
